using System;using System.Data.SQLite;using System.IO;using System.Text;namespace DataMigration.Tools{class Program{static void Main(string[] args){// 创建数据源数据库CreateSourceDatabase();// 创建目标源数据库CreateTargetDatabase();Console.WriteLine("数据库创建完成！");}static void CreateSourceDatabase(){string dbPath = Path.Combine(Directory.GetCurrentDirectory(), "data", "source.db");// 删除已存在的文件if (File.Exists(dbPath)){File.Delete(dbPath);}// 创建数据库using (SQLiteConnection conn = new SQLiteConnection($"Data Source={dbPath}")){conn.Open();// 创建用户表CreateUserTable(conn);// 创建订单表CreateOrderTable(conn);// 创建产品表CreateProductTable(conn);// 填充测试数据InsertTestData(conn);conn.Close();}}static void CreateTargetDatabase(){string dbPath = Path.Combine(Directory.GetCurrentDirectory(), "data", "target.db");// 删除已存在的文件if (File.Exists(dbPath)){File.Delete(dbPath);}// 创建数据库using (SQLiteConnection conn = new SQLiteConnection($"Data Source={dbPath}")){conn.Open();// 创建用户表（与源数据库相同）CreateUserTable(conn);// 创建订单表（与源数据库相同）CreateOrderTable(conn);// 创建产品表（与源数据库相同）CreateProductTable(conn);conn.Close();}}static void CreateUserTable(SQLiteConnection conn){string sql = @"CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, email TEXT NOT NULL, age INTEGER, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);";using (SQLiteCommand cmd = new SQLiteCommand(sql, conn)){cmd.ExecuteNonQuery();}}static void CreateOrderTable(SQLiteConnection conn){string sql = @"CREATE TABLE IF NOT EXISTS orders (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL, product_id INTEGER NOT NULL, amount DECIMAL(10, 2) NOT NULL, status TEXT NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id), FOREIGN KEY (product_id) REFERENCES products(id));";using (SQLiteCommand cmd = new SQLiteCommand(sql, conn)){cmd.ExecuteNonQuery();}}static void CreateProductTable(SQLiteConnection conn){string sql = @"CREATE TABLE IF NOT EXISTS products (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, price DECIMAL(10, 2) NOT NULL, stock INTEGER NOT NULL, category TEXT NOT NULL);";using (SQLiteCommand cmd = new SQLiteCommand(sql, conn)){cmd.ExecuteNonQuery();}}static void InsertTestData(SQLiteConnection conn){// 插入用户数据string[] users = {@"('Alice', 'alice@example.com', 25)",@"('Bob', 'bob@example.com', 30)",@"('Charlie', 'charlie@example.com', 35)",@"('David', 'david@example.com', 28)",@"('Eve', 'eve@example.com', 32)",@"('Frank', 'frank@example.com', 40)",@"('Grace', 'grace@example.com', 22)",@"('Henry', 'henry@example.com', 29)",@"('Ivy', 'ivy@example.com', 31)",@"('Jack', 'jack@example.com', 33)"};string userSql = "INSERT INTO users (name, email, age) VALUES " + string.Join(", ", users) + ";";using (SQLiteCommand cmd = new SQLiteCommand(userSql, conn)){cmd.ExecuteNonQuery();}// 插入产品数据string[] products = {@"('Product A', 19.99, 100, 'Electronics')",@"('Product B', 29.99, 50, 'Clothing')",@"('Product C', 9.99, 200, 'Home')",@"('Product D', 49.99, 30, 'Electronics')",@"('Product E', 14.99, 150, 'Clothing')",@"('Product F', 24.99, 80, 'Home')",@"('Product G', 39.99, 40, 'Electronics')",@"('Product H', 12.99, 120, 'Clothing')",@"('Product I', 8.99, 250, 'Home')",@"('Product J', 59.99, 20, 'Electronics')"};string productSql = "INSERT INTO products (name, price, stock, category) VALUES " + string.Join(", ", products) + ";";using (SQLiteCommand cmd = new SQLiteCommand(productSql, conn)){cmd.ExecuteNonQuery();}// 插入订单数据StringBuilder orderSql = new StringBuilder("INSERT INTO orders (user_id, product_id, amount, status) VALUES ");string[] orders = {@"(1, 1, 19.99, 'Completed')",@"(1, 2, 29.99, 'Pending')",@"(2, 3, 9.99, 'Completed')",@"(2, 4, 49.99, 'Completed')",@"(3, 5, 14.99, 'Pending')",@"(3, 6, 24.99, 'Completed')",@"(4, 7, 39.99, 'Pending')",@"(4, 8, 12.99, 'Completed')",@"(5, 9, 8.99, 'Completed')",@"(5, 10, 59.99, 'Pending')",@"(6, 1, 19.99, 'Completed')",@"(6, 3, 9.99, 'Completed')",@"(7, 2, 29.99, 'Pending')",@"(7, 4, 49.99, 'Completed')",@"(8, 5, 14.99, 'Completed')",@"(8, 7, 39.99, 'Pending')",@"(9, 6, 24.99, 'Completed')",@"(9, 8, 12.99, 'Completed')",@"(10, 9, 8.99, 'Pending')",@"(10, 10, 59.99, 'Completed')"};orderSql.Append(string.Join(", ", orders));orderSql.Append(";").AppendLine();using (SQLiteCommand cmd = new SQLiteCommand(orderSql.ToString(), conn)){cmd.ExecuteNonQuery();}}}}}